INSERT INTO memory_nodes
  (id,schema_version,workspace_id,title_zh,title_en,content_type,content_format,
   body_zh,body_en,tags,visibility,author,created_at,signature,source_type,
   trust_score,dim_accuracy,dim_freshness,dim_utility,dim_author_rep,
   votes_up,votes_down,verifications,traversal_count,unique_traverser_count)
VALUES
  ('mem_g003','1.0','ws_spec0001','Edge 關係類型：四種語意方向','Edge relation types: four semantic directions','factual','markdown',
   '| Relation | 語意 | 使用時機 |
|----------|------|----------|
| `depends_on` | 來源節點的成立依賴目標節點 | A 的流程前提是 B 的概念 |
| `extends` | 來源節點延伸或補充目標節點 | A 是 B 的進階版本 |
| `related_to` | 有相關性但無明確依賴方向 | A 和 B 都屬於同一主題 |
| `contradicts` | 來源節點的內容與目標節點矛盾 | A 的結論與 B 相衝突 |

選擇正確的 relation type 很重要，因為它決定了 co-access boost 的強度，以及 AI agent 在遍歷圖時如何解讀關係。','| Relation | Semantics | When to use |
|----------|-----------|-------------|
| `depends_on` | Source requires target to be valid | A''s process presupposes B''s concept |
| `extends` | Source extends or supplements target | A is an advanced version of B |
| `related_to` | Related without clear dependency direction | A and B belong to the same topic |
| `contradicts` | Source conflicts with target | A''s conclusion conflicts with B |

Choosing the correct relation type matters: it determines co-access boost strength and how AI agents interpret the relationship when traversing the graph.',ARRAY['graph-mechanics', 'relation-type', 'edge', 'schema']::text[],'public',
   'memtrace-spec','2026-04-11T00:00:00Z','f7a2b3c4d5e6f7a2b3c4d5e6f7a2b3c4d5e6f7a2b3c4d5e6f7a2b3c4d5e6f7a2','human',
   0.95,0.95,1.0,0.95,0.9,
   0,0,0,0,0)
